template:
class_name StateMachine
extends Node

## Emitted when the active state changes
signal state_changed(old_state: State, new_state: State)

## The initial state (set in editor)
@export var initial_state: State

## Current active state
var current_state: State

## All registered states
var _states: Dictionary = {}


func _ready() -> void:
	for child in get_children():
		if child is State:
			_states[child.name.to_lower()] = child
			child.state_machine = self

	if initial_state:
		current_state = initial_state
		current_state.enter()


func _process(delta: float) -> void:
	if current_state:
		current_state.update(delta)


func _physics_process(delta: float) -> void:
	if current_state:
		current_state.physics_update(delta)


func _unhandled_input(event: InputEvent) -> void:
	if current_state:
		current_state.handle_input(event)


func transition_to(target_state_name: String, data: Dictionary = {}) -> void:
	var target_state: State = _states.get(target_state_name.to_lower())
	if not target_state:
		push_warning("State '%s' not found in StateMachine" % target_state_name)
		return
	if target_state == current_state:
		return

	var old_state := current_state
	current_state.exit()
	current_state = target_state
	current_state.enter(data)
	state_changed.emit(old_state, current_state)
